import{_ as t,o as i,c as r,ag as a}from"./chunks/framework.B9unkguw.js";const u=JSON.parse('{"title":"Scripting (ArduPilot)","description":"","frontmatter":{},"headers":[],"relativePath":"zh/qgc-user-guide/setup_view/ardupilot/scripting.md","filePath":"zh/qgc-user-guide/setup_view/ardupilot/scripting.md"}'),o={name:"zh/qgc-user-guide/setup_view/ardupilot/scripting.md"};function l(n,e,s,c,p,d){return i(),r("div",null,e[0]||(e[0]=[a('<h1 id="scripting-ardupilot" tabindex="-1">Scripting (ArduPilot) <a class="header-anchor" href="#scripting-ardupilot" aria-label="Permalink to &quot;Scripting (ArduPilot)&quot;">​</a></h1><p>The Scripting page manages Lua scripts on ArduPilot vehicles that support onboard scripting.</p><h2 id="enable-scripting" tabindex="-1">Enable Scripting <a class="header-anchor" href="#enable-scripting" aria-label="Permalink to &quot;Enable Scripting&quot;">​</a></h2><ul><li><strong>Enable Scripting</strong> — toggle the <code>SCR_ENABLE</code> parameter to allow Lua scripts to run on the flight controller</li></ul><h2 id="script-management" tabindex="-1">Script Management <a class="header-anchor" href="#script-management" aria-label="Permalink to &quot;Script Management&quot;">​</a></h2><p>Scripts are stored in the <code>/APM/scripts/</code> directory on the vehicle&#39;s SD card. The page provides:</p><ul><li><strong>Upload</strong> — select a <code>.lua</code> file from your computer and upload it to the vehicle via MAVLink FTP</li><li><strong>Script list</strong> — shows all <code>.lua</code> files currently on the vehicle <ul><li><strong>Download</strong> — save a script from the vehicle to your local filesystem</li><li><strong>Delete</strong> — remove a script from the vehicle (with confirmation dialog)</li></ul></li></ul><p>After uploading or deleting scripts, you may need to reboot the flight controller for changes to take effect.</p>',8)]))}const h=t(o,[["render",l]]);export{u as __pageData,h as default};
